import React from "react";

function GridOptions( ifGridSelected=false){
    if (ifGridSelected === true)
        return (
            <div className="GridOptions">
                <label for="gridRows">grid-row: </label>
                <input name="gridRows"></input>
            </div>
        );
}

export default GridOptions;
